-- =============================================
-- UPDATE: email takedrop_account_inactive — link aktywacyjny TakeDrop
-- Glowne CTA = link pay (aktywacja konta + 21 dni za darmo),
-- panel projektu jako link drugorzedny pod przyciskiem.
-- =============================================

INSERT INTO settings (key, value) VALUES (
  'email_template_takedrop_account_inactive_body',
  '<!DOCTYPE html><html><head><meta charset="utf-8"><meta name="viewport" content="width=device-width, initial-scale=1.0"></head><body style="margin:0;padding:0;font-family:-apple-system,BlinkMacSystemFont,''Segoe UI'',Roboto,''Helvetica Neue'',Arial,sans-serif;background-color:#000000;"><table width="100%" cellpadding="0" cellspacing="0" style="background-color:#000000;padding:40px 20px;"><tr><td align="center"><table width="560" cellpadding="0" cellspacing="0" style="background-color:#0a0a0a;border-radius:12px;border:1px solid #262626;"><tr><td style="padding:48px 40px 40px 40px;"><p style="margin:0 0 8px 0;color:#f59e0b;font-size:12px;font-weight:600;text-transform:uppercase;letter-spacing:1px;">⚠️ Konto nieaktywne</p><h1 style="margin:0 0 20px 0;color:#ffffff;font-size:26px;font-weight:600;line-height:1.3;">Cześć {{clientName}}!</h1><p style="margin:0 0 16px 0;color:#a3a3a3;font-size:15px;line-height:1.65;">Zajrzałem do Twojego konta TakeDrop — logowanie działa, ale konto jest wciąż <strong style="color:#fbbf24;">nieaktywne</strong>: brak podpiętej karty płatniczej, więc TakeDrop blokuje sklep. Cofnąłem status aktywacji — na zablokowanym koncie nie możemy konfigurować Twojego sklepu.</p><p style="margin:0 0 16px 0;color:#a3a3a3;font-size:15px;line-height:1.65;">Dobra wiadomość: przygotowałem link aktywacyjny — podpinasz kartę i dostajesz <strong style="color:#fbbf24;">21 dni za darmo</strong>.</p><p style="margin:0 0 24px 0;color:#a3a3a3;font-size:15px;line-height:1.65;"><strong style="color:#ffffff;">Co zrobić:</strong></p><ol style="margin:0 0 28px 0;padding-left:20px;color:#a3a3a3;font-size:15px;line-height:1.85;"><li>Kliknij przycisk poniżej i podepnij kartę — konto aktywuje się od razu, a pierwsze <strong style="color:#fbbf24;">21 dni masz za darmo</strong></li><li>Zaloguj się na <a href="https://app.takedrop.pl/login" style="color:#fbbf24;text-decoration:none;">app.takedrop.pl</a> i upewnij się, że komunikat o blokadzie zniknął</li><li>Wróć do panelu projektu i kliknij <strong style="color:#ffffff;">„Konto działa — potwierdzam aktywację"</strong></li></ol><table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:14px;"><tr><td align="center"><a href="https://app.takedrop.pl/pay/0f949713-70a6-4968-af37-9400ed886baa" style="display:inline-block;background:linear-gradient(135deg,#f59e0b 0%,#d97706 100%);color:#ffffff;text-decoration:none;padding:15px 32px;border-radius:8px;font-size:14px;font-weight:700;text-align:center;">Aktywuj konto — 21 dni za darmo →</a></td></tr><tr><td align="center" style="padding-top:14px;"><a href="{{projectUrl}}" style="color:#a3a3a3;font-size:13px;text-decoration:underline;">Otwórz panel projektu →</a></td></tr></table><p style="margin:24px 0 0 0;padding:18px;background:#171717;border-radius:8px;color:#737373;font-size:13px;line-height:1.55;">Jak tylko potwierdzę, że konto jest aktywne — wracamy do podłączania strony i konfiguracji płatności.</p></td></tr><tr><td style="padding:18px 40px;border-top:1px solid #262626;text-align:center;"><a href="https://tomekniedzwiecki.pl" style="color:#525252;font-size:12px;text-decoration:none;">tomekniedzwiecki.pl</a></td></tr></table></td></tr></table></body></html>'
) ON CONFLICT (key) DO UPDATE SET value = EXCLUDED.value;
